INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アヤネ", 24, 24001, 2, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 102301, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 401, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アヤネ", 24, 24002, 1, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 102301, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 402, 10046, 2.21);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アヤネ", 24, 24003, 2, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 102301, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 403, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アサヒ", 24, 24004, 2, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 192201, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 701, 10046, 1.99);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アサヒ", 24, 24005, 1, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 192201, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 702, 10046, 2.21);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アサヒ", 24, 24006, 2, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 192201, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 703, 10046, 3.33);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "部員３", 24, 24007, 2, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 192301, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 801, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "部員３", 24, 24008, 1, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 192301, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 802, 10046, 2.68);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "部員３", 24, 24009, 2, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 192301, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 803, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "", 24, 24010, 1, "やった！", 192501, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 501, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "", 24, 24011, 1, "勝ったよ！", 192501, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 502, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "", 24, 24012, 1, "いい調子！", 192501, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 503, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ミサト", 24, 24013, 6, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 113501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 111, 10046, 5.33);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ミサト", 24, 24014, 1, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 113501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 112, 10046, 6.85);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ミサト", 24, 24015, 1, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 113501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 113, 10046, 3.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ダイチ", 24, 24016, 1, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 192401, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 611, 10046, 6.11);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ダイチ", 24, 24017, 1, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 192401, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 612, 10046, 6.75);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ダイチ", 24, 24018, 2, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 192401, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 613, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ハツネ", 24, 24019, 2, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 113401, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 211, 10046, 4.52);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ハツネ", 24, 24020, 2, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 113401, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 212, 10046, 3.89);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "ハツネ", 24, 24021, 1, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 113401, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 213, 10046, 13.49);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "カヤ", 24, 24022, 1, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 106501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 311, 10046, 3.17);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "カヤ", 24, 24023, 1, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 106501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 312, 10046, 4.42);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "カヤ", 24, 24024, 6, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 106501, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 313, 10046, 2.89);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アヤネ", 24, 24025, 4, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 102301, "2020/07/31 12:00:00", 3, 0.0, "2030/12/17 14:59:59", 421, 10046, 3.71);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "アサヒ", 24, 24026, 2, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 192201, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 721, 10046, 5.1);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "部員３", 24, 24027, 1, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 192301, "2020/07/31 12:00:00", 3, 0.0, "2030/12/17 14:59:59", 821, 10046, 4.34);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (0.0, "", 24, 24028, 1, "いい勝負だったよ\nまたやろうね", 192501, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 521, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (-360.0, "ミサト", 24, 24029, 1, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 113501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 101, 10046, 5.62);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (-360.0, "ミサト", 24, 24030, 1, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 113501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 102, 10046, 9.58);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (-360.0, "ミサト", 24, 24031, 2, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 113501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 103, 10046, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (-360.0, "ミサト", 24, 24032, 2, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 113501, "2020/07/31 12:00:00", 1, 0.0, "2030/12/17 14:59:59", 104, 10046, 9.13);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES (-360.0, "ミサト", 24, 24033, 1, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 113501, "2020/07/31 12:00:00", 2, 0.0, "2030/12/17 14:59:59", 105, 10046, 8.27);
